// CLX Intelligence Upsell Detector v1 — Build summary email
// Takes the result of Query Missed Signal Clients and composes one
// Gmail send to info@crystallux.org summarising upsell candidates.
// TESTING MODE preserved: routes through the same
// adesholaakintunde+clxtest@gmail.com redirect as other senders.

const rows = $input.item.json;
const candidates = Array.isArray(rows) ? rows : [];

if (candidates.length === 0) {
  return { json: { _skip: true, reason: 'no_upsell_candidates_this_week' } };
}

const today = new Date().toISOString().split('T')[0];
const subject = 'Crystallux upsell alert: ' + candidates.length + ' clients missed high-impact signals this week';
const to = 'adesholaakintunde+clxtest@gmail.com'; // TESTING MODE — remove before production
const fromName = 'Crystallux Intelligence';
const fromEmail = 'info@crystallux.org';

const rowsHtml = candidates.map(c => {
  return '<tr><td style="padding:8px;border-bottom:1px solid #eee;">' + (c.client_name || '—') + '</td>' +
    '<td style="padding:8px;border-bottom:1px solid #eee;">' + (c.vertical || '—') + '</td>' +
    '<td style="padding:8px;border-bottom:1px solid #eee;text-align:right;">' + (c.missed_signals || 0) + '</td></tr>';
}).join('');

const htmlBody = [
  '<div style="font-family:Arial,Helvetica,sans-serif;max-width:620px;margin:0 auto;color:#1a202c;">',
  '  <h2 style="color:#2563eb;">' + candidates.length + ' Intelligence-tier upsell opportunities</h2>',
  '  <p>Clients who would have benefited from the Market Intelligence tier this past week. Each had 3+ active signals affecting their vertical. Consider reaching out to upgrade them before next week\'s signals arrive.</p>',
  '  <table style="width:100%;border-collapse:collapse;margin-top:16px;">',
  '    <thead><tr><th style="text-align:left;padding:8px;background:#f4f5f9;">Client</th><th style="text-align:left;padding:8px;background:#f4f5f9;">Vertical</th><th style="text-align:right;padding:8px;background:#f4f5f9;">Missed signals</th></tr></thead>',
  '    <tbody>' + rowsHtml + '</tbody>',
  '  </table>',
  '  <p style="margin-top:24px;"><a href="https://crystallux.org/dashboard?token=MARY_MASTER_TOKEN" style="background:#2563eb;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;font-weight:600;">Open admin dashboard</a></p>',
  '  <p style="font-size:12px;color:#718096;margin-top:16px;">Weekly report generated ' + today + ' by clx-intelligence-upsell-detector-v1. To change cadence or disable, open the workflow in n8n.</p>',
  '</div>'
].join('\n');

const encodedSubject = '=?UTF-8?B?' + Buffer.from(subject, 'utf8').toString('base64') + '?=';
const mime = [
  'From: "' + fromName + '" <' + fromEmail + '>',
  'To: ' + to,
  'Subject: ' + encodedSubject,
  'MIME-Version: 1.0',
  'Content-Type: text/html; charset=utf-8',
  'Content-Transfer-Encoding: 7bit',
  '',
  htmlBody
].join('\r\n');

const raw = Buffer.from(mime, 'utf8').toString('base64')
  .replace(/\+/g, '-')
  .replace(/\//g, '_')
  .replace(/=+$/, '');

return { json: { gmail_raw: raw, to_address: to, candidate_count: candidates.length } };
